<?php
namespace ChupaHub\Middleware;final class Security{public static function apply(string $cors):void{header("Access-Control-Allow-Origin: $cors");header('Access-Control-Allow-Headers: Authorization, Content-Type, X-CSRF-Token');header('Access-Control-Allow-Methods: GET, POST, PUT, DELETE, OPTIONS');header('X-Content-Type-Options: nosniff');header('Referrer-Policy: strict-origin-when-cross-origin');if($_SERVER['REQUEST_METHOD']==='OPTIONS')exit;}public static function input(array $data,array $rules):array{$out=[];foreach($rules as $k=>$type){$v=$data[$k]??null;$out[$k]=match($type){'email'=>filter_var($v,FILTER_VALIDATE_EMAIL)?:null,'int'=>filter_var($v,FILTER_VALIDATE_INT),'float'=>filter_var($v,FILTER_VALIDATE_FLOAT),'string'=>trim(strip_tags((string)$v)),default=>$v};}return $out;}}
